#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<string> generate(int n) {
        vector<string> res;
        string cur;
        cur.reserve(n);
        function<void(int,bool)> dfs = [&](int pos, bool prev_one) {
            if (pos == n) {
                res.push_back(cur);
                return;
            }
            // place '0'
            cur.push_back('0');
            dfs(pos + 1, false);
            cur.pop_back();
            // place '1' if allowed
            if (!prev_one) {
                cur.push_back('1');
                dfs(pos + 1, true);
                cur.pop_back();
            }
        };
        dfs(0, false);
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    vector<string> ans = sol.generate(n);
    cout << ans.size() << "\n";
    for (const string &s : ans) {
        cout << s << "\n";
    }
    return 0;
}
